import { Avatar, Card, CardActionArea, CardContent, CardHeader, CardMedia, Divider, Typography } from '@material-ui/core'
import { makeStyles } from '@material-ui/styles'
import subjectPhoto from ' ../images/phil.png'
import React from 'react'

const useStyle = makeStyles(theme => {
  return {
    root: {
      '& .MuiCardActionArea-focusHighlight': {
      background: 'none'
    }
    
  },
  avatar: {
    background: '#162276',
    width: theme.spacing(7),
    height: theme.spacing(7),
  }
}})

export default function SubjectCards({ subject }) {
  const classes = useStyle()
  return (
    <div>
      <Card className={classes.root}>
        <CardActionArea>
        <CardMedia
        className={classes.media}
        image=".../images/"
        title="Paella dish"
      />
          <CardHeader
            avatar={
              <Avatar className={classes.avatar} sizes='medium'>
                P
              </Avatar>
            }

            title={subject.title}
            subheader={subject.instructor}
          />

          <Divider />
          <CardContent>
            <Typography>
              {subject.body}
            </Typography>
          </CardContent>
        </CardActionArea>
      </Card>
    </div>
  )
}
